const laws = [
  { law_id: '08381293-6388-48e2-8ad2-a9a700f2aa94', law_name: 'نظام العمل', category: 'labor_law' },
  { law_id: '25df73d6-0f49-4dc5-b010-a9a700f2ec1d', law_name: 'نظام مكافحة جرائم المعلوماتية', category: 'cyber_crimes' },
  { law_id: '6f509360-2c39-4358-ae2a-a9a700f2ed16', law_name: 'نظام التعاملات الإلكترونية', category: 'ecommerce' },
  { law_id: 'c2c05ee1-201a-48de-91e7-a9a700f2d14f', law_name: 'نظام المنافسات والمشتريات الحكومية', category: 'procurement' },
  { law_id: '23576008-1ce4-4685-ac3e-a9a700f2cb02', law_name: 'نظام ضريبة الدخل', category: 'tax' },
  { law_id: 'ae610645-e094-48ef-814e-aeb4009d244f', law_name: 'نظام الاتصالات وتقنية المعلومات', category: 'telecom' },
  { law_id: 'eda86cc3-3a00-4b90-900d-b1d000c8a863', law_name: 'نظام الاستثمار', category: 'investment' },
  { law_id: '85364e57-c01e-41ba-8def-a9a700f183e9', law_name: 'نظام المرور', category: 'traffic' },
  { law_id: '98ee4b51-d398-4323-ae69-b2b8009f3156', law_name: 'نظام السجل التجاري', category: 'commercial_registry' },
  { law_id: '93e87aa7-f344-4711-b97c-a9a700f1662b', law_name: 'نظام مجلس الوزراء', category: 'government' },
  { law_id: 'b5cf540a-e6ac-426a-b348-a9a700f163de', law_name: 'نظام مجلس الشورى', category: 'government' },
  { law_id: '93f81644-fbbc-49ca-b33c-a9a700f16701', law_name: 'نظام المناطق', category: 'regions' }
];

return laws.map(law => ({
  json: {
    ...law,
    url: `https://laws.boe.gov.sa/BoeLaws/Laws/LawDetails/${law.law_id}/1`,
    source: 'laws.boe.gov.sa'
  }
}));

// استخراج نص القانون من HTML وتقسيمه إلى أجزاء
const chunkSize = 800;
const overlap = 100;
const results = [];

// الحصول على بيانات القانون من SplitInBatches
const batchNode = $('🔄 معالجة واحد تلو الآخر');
const meta = batchNode.item.json;
const lawName = meta.law_name || 'unknown';
const lawId = meta.law_id || 'unknown';
const source = meta.source || 'boe.gov.sa';
const category = meta.category || '';

// الحصول على HTML من HTTP Response
let html = '';
if (typeof $json === 'string') {
  html = $json;
} else if ($json.data && typeof $json.data === 'string') {
  html = $json.data;
} else {
  html = JSON.stringify($json);
}

// تنظيف HTML
let text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<[^>]+>/g, ' ');
text = text.replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"');
text = text.replace(/\s+/g, ' ').trim();

// البحث عن بداية نص النظام
const markers = ['نـــص النظـــام', 'نص النظام', 'المادة الأولى'];
let startIdx = -1;
for (const m of markers) {
  startIdx = text.indexOf(m);
  if (startIdx > -1) break;
}
if (startIdx > -1) text = text.substring(startIdx);

// إزالة الفوتر
const footerMarkers = ['جميع الحقوق محفوظة', 'go to top', 'Additional Links'];
for (const m of footerMarkers) {
  const idx = text.indexOf(m);
  if (idx > -1) text = text.substring(0, idx);
}
text = text.trim();

if (text.length < 100) {
  return [{ json: { error: `النص قصير جداً: ${lawName}`, length: text.length } }];
}

// تقسيم النص
let start = 0, chunkIdx = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.substring(start, end).trim();
  if (chunk.length > 50) {
    results.push({
      json: {
        chunk_id: `boe_${category}_c${chunkIdx}`,
        chunk_text: chunk,
        law_name: lawName,
        law_id: lawId,
        source: source,
        category: category,
        chunk_index: chunkIdx,
        total_text_length: text.length
      }
    });
    chunkIdx++;
  }
  if (end >= text.length) break;
  start += chunkSize - overlap;
}

return results;

// دمج بيانات Embedding مع بيانات القطعة
const embedding = $json.embedding;
const prev = $('✂️ استخراج وتقسيم النص').item.json;

return {
  ids: [prev.chunk_id],
  embeddings: [embedding],
  documents: [prev.chunk_text],
  metadatas: [{
    law_name: prev.law_name,
    law_id: prev.law_id,
    source: prev.source,
    category: prev.category,
    chunk_index: prev.chunk_index,
    ingested_at: new Date().toISOString()
  }],
  chunk_id: prev.chunk_id,
  law_name: prev.law_name
};

// تقرير نهائي
const items = $input.all();
const successCount = items.filter(i => !i.json.error).length;
const errorCount = items.filter(i => i.json.error).length;

return [{
  json: {
    total_chunks_saved: successCount,
    errors: errorCount,
    message: `✅ تم حفظ ${successCount} قطعة في ChromaDB بنجاح`,
    timestamp: new Date().toISOString()
  }
}];

